void UInsimulPauseMenuWidget::NativeConstruct()
{
    Super::NativeConstruct();

    RootCanvas = WidgetTree->ConstructWidget<UCanvasPanel>(UCanvasPanel::StaticClass(), TEXT("RootCanvas"));
    WidgetTree->RootWidget = RootCanvas;

    // Semi-transparent background overlay
    UImage* Overlay = WidgetTree->ConstructWidget<UImage>(UImage::StaticClass(), TEXT("Overlay"));
    UCanvasPanelSlot* OvSlot = RootCanvas->AddChildToCanvas(Overlay);
    OvSlot->SetAnchors(FAnchors(0.f, 0.f, 1.f, 1.f));
    OvSlot->SetOffsets(FMargin(0.f));
    Overlay->SetColorAndOpacity(FLinearColor(0.f, 0.f, 0.f, 0.6f));

    BuildMainPanel();
    SetVisibility(ESlateVisibility::Collapsed);
}

bool UInsimulPauseMenuWidget::TogglePauseMenu()
{
    if (GetVisibility() == ESlateVisibility::Visible)
    {
        ClosePauseMenu();
        return false;
    }

    ShowMainPanel();
    SetVisibility(ESlateVisibility::Visible);
    SetPaused(true);
    return true;
}

void UInsimulPauseMenuWidget::ClosePauseMenu()
{
    SetVisibility(ESlateVisibility::Collapsed);
    SetPaused(false);
}

void UInsimulPauseMenuWidget::SetPaused(bool bPause)
{
    APlayerController* PC = GetOwningPlayer();
    if (!PC) return;

    UGameplayStatics::SetGamePaused(this, bPause);
    if (bPause)
    {
        PC->SetShowMouseCursor(true);
        PC->SetInputMode(FInputModeUIOnly());
    }
    else
    {
        PC->SetShowMouseCursor(false);
        PC->SetInputMode(FInputModeGameOnly());
    }
}

