{
    MainPanel = WidgetTree->ConstructWidget<UVerticalBox>(UVerticalBox::StaticClass(), TEXT("MainPanel"));
    UCanvasPanelSlot* Slot = RootCanvas->AddChildToCanvas(MainPanel);
    Slot->SetAnchors(FAnchors(0.5f, 0.5f, 0.5f, 0.5f));
    Slot->SetAlignment(FVector2D(0.5f, 0.5f));
    Slot->SetSize(FVector2D(400.f, 500.f));

    // Title
    UTextBlock* Title = WidgetTree->ConstructWidget<UTextBlock>(UTextBlock::StaticClass(), TEXT("PauseTitle"));
    Title->SetText(FText::FromString(TEXT("Paused")));
    FSlateFontInfo TitleFont = Title->GetFont();
    TitleFont.Size = 42;
    Title->SetFont(TitleFont);
    Title->SetJustification(ETextJustify::Center);
    Title->SetColorAndOpacity(FSlateColor(FLinearColor::White));
    UVerticalBoxSlot* TitleSlot = MainPanel->AddChildToVerticalBox(Title);
    TitleSlot->SetHorizontalAlignment(HAlign_Center);
    TitleSlot->SetPadding(FMargin(0.f, 0.f, 0.f, 30.f));

    // Buttons
    UButton* ResumeBtn = CreateMenuButton(TEXT("Resume"), MainPanel);
    ResumeBtn->OnClicked.AddDynamic(this, &UInsimulPauseMenuWidget::OnResumeClicked);

    UButton* SaveBtn = CreateMenuButton(TEXT("Save Game"), MainPanel);
    SaveBtn->OnClicked.AddDynamic(this, &UInsimulPauseMenuWidget::OnSaveGameClicked);

    UButton* LoadBtn = CreateMenuButton(TEXT("Load Game"), MainPanel);
    LoadBtn->OnClicked.AddDynamic(this, &UInsimulPauseMenuWidget::OnLoadGameClicked);

    UButton* SettingsBtn = CreateMenuButton(TEXT("Settings"), MainPanel);
    SettingsBtn->OnClicked.AddDynamic(this, &UInsimulPauseMenuWidget::OnSettingsClicked);

    UButton* QuitBtn = CreateMenuButton(TEXT("Quit to Main Menu"), MainPanel);
    QuitBtn->OnClicked.AddDynamic(this, &UInsimulPauseMenuWidget::OnQuitToMenuClicked);
}

void UInsimulPauseMenuWidget::BuildSaveLoadPanel(bool bIsSaveMode)
{
    bCurrentlySaveMode = bIsSaveMode;

    // Destroy previous save/load panel if it exists
    if (SaveLoadPanel)
    {
        SaveLoadPanel->RemoveFromParent();
        SaveLoadPanel = nullptr;
    }

    SaveLoadPanel = WidgetTree->ConstructWidget<UVerticalBox>(UVerticalBox::StaticClass(), TEXT("SaveLoadPanel"));
    UCanvasPanelSlot* Slot = RootCanvas->AddChildToCanvas(SaveLoadPanel);
    Slot->SetAnchors(FAnchors(0.5f, 0.5f, 0.5f, 0.5f));
    Slot->SetAlignment(FVector2D(0.5f, 0.5f));
    Slot->SetSize(FVector2D(450.f, 550.f));

    // Title
    SaveLoadTitle = WidgetTree->ConstructWidget<UTextBlock>(UTextBlock::StaticClass(), TEXT("SaveLoadTitle"));
    SaveLoadTitle->SetText(FText::FromString(bIsSaveMode ? TEXT("Save Game") : TEXT("Load Game")));
    FSlateFontInfo TitleFont = SaveLoadTitle->GetFont();
    TitleFont.Size = 36;
    SaveLoadTitle->SetFont(TitleFont);
    SaveLoadTitle->SetJustification(ETextJustify::Center);
    SaveLoadTitle->SetColorAndOpacity(FSlateColor(FLinearColor::White));
    UVerticalBoxSlot* TitleSlot = SaveLoadPanel->AddChildToVerticalBox(SaveLoadTitle);
    TitleSlot->SetHorizontalAlignment(HAlign_Center);
    TitleSlot->SetPadding(FMargin(0.f, 0.f, 0.f, 20.f));

    // Generate slot buttons
    for (int32 i = 0; i < MaxSaveSlots; ++i)
    {
        FString SlotName = FString::Printf(TEXT("InsimulSave_%d"), i);
        bool bSlotExists = UGameplayStatics::DoesSaveGameExist(SlotName, 0);

        FString Label;
        if (bSlotExists)
        {
            UInsimulSaveGame* ExistingSave = Cast<UInsimulSaveGame>(UGameplayStatics::LoadGameFromSlot(SlotName, 0));
            if (ExistingSave)
            {
                Label = FString::Printf(TEXT("Slot %d — %s"), i + 1, *ExistingSave->SaveDisplayName);
            }
            else
            {
                Label = FString::Printf(TEXT("Slot %d — Saved"), i + 1);
            }
        }
        else
        {
            Label = FString::Printf(TEXT("Slot %d — Empty"), i + 1);
        }

        UButton* SlotBtn = CreateMenuButton(Label, SaveLoadPanel);

        // For load mode, disable empty slots
        if (!bIsSaveMode && !bSlotExists)
        {
            SlotBtn->SetIsEnabled(false);
        }

        // Bind using a lambda captured delegate
        int32 CapturedIndex = i;
        if (bIsSaveMode)
        {
            SlotBtn->OnClicked.AddDynamic(this, &UInsimulPauseMenuWidget::OnSaveLoadBackClicked);
            // Override: use per-slot save via blueprint or C++ workaround
            FScriptDelegate Del;
            SlotBtn->OnClicked.Clear();
            // Use a simple approach: tag the button with the slot index
            SlotBtn->SetTag(FString::FromInt(i));
        }
        else
        {
            SlotBtn->SetTag(FString::FromInt(i));
        }
    }

    // Back button
    UButton* BackBtn = CreateMenuButton(TEXT("Back"), SaveLoadPanel);
    BackBtn->OnClicked.AddDynamic(this, &UInsimulPauseMenuWidget::OnSaveLoadBackClicked);
}

UButton* UInsimulPauseMenuWidget::CreateMenuButton(const FString& Label, UVerticalBox* Parent)
{
    UButton* Btn = WidgetTree->ConstructWidget<UButton>(UButton::StaticClass());
    Btn->SetBackgroundColor(FLinearColor(0.12f, 0.12f, 0.18f, 0.9f));

    UTextBlock* BtnText = WidgetTree->ConstructWidget<UTextBlock>(UTextBlock::StaticClass());
    BtnText->SetText(FText::FromString(Label));
    FSlateFontInfo BtnFont = BtnText->GetFont();
    BtnFont.Size = 20;
    BtnText->SetFont(BtnFont);
    BtnText->SetJustification(ETextJustify::Center);
    BtnText->SetColorAndOpacity(FSlateColor(FLinearColor::White));
    Btn->AddChild(BtnText);

    UVerticalBoxSlot* BtnSlot = Parent->AddChildToVerticalBox(Btn);
    BtnSlot->SetHorizontalAlignment(HAlign_Center);
    BtnSlot->SetPadding(FMargin(0.f, 6.f, 0.f, 6.f));

    return Btn;
}

void UInsimulPauseMenuWidget::ShowMainPanel()
{
    MainPanel->SetVisibility(ESlateVisibility::Visible);
    if (SaveLoadPanel)
    {
        SaveLoadPanel->SetVisibility(ESlateVisibility::Collapsed);
    }
}

void UInsimulPauseMenuWidget::ShowSaveLoadPanel()
{
    MainPanel->SetVisibility(ESlateVisibility::Collapsed);
    if (SaveLoadPanel)
    {
        SaveLoadPanel->SetVisibility(ESlateVisibility::Visible);
    }
}

