void UInsimulPauseMenuWidget::OnSaveSlotClicked(int32 SlotIndex)
{
    FString SlotName = FString::Printf(TEXT("InsimulSave_%d"), SlotIndex);
    UInsimulSaveGame* SaveInstance = Cast<UInsimulSaveGame>(UGameplayStatics::CreateSaveGameObject(UInsimulSaveGame::StaticClass()));
    if (!SaveInstance) return;

    // Populate save data from current game state
    APawn* PlayerPawn = GetOwningPlayerPawn();
    if (PlayerPawn)
    {
        SaveInstance->PlayerLocation = PlayerPawn->GetActorLocation();
        SaveInstance->PlayerRotation = PlayerPawn->GetActorRotation();
    }

    SaveInstance->SaveDisplayName = FDateTime::Now().ToString(TEXT("%Y-%m-%d %H:%M"));

    UGameplayStatics::SaveGameToSlot(SaveInstance, SlotName, 0);
    UE_LOG(LogTemp, Log, TEXT("[InsimulPauseMenu] Game saved to slot %d"), SlotIndex);

    // Refresh the panel to show updated slot info
    BuildSaveLoadPanel(true);
    ShowSaveLoadPanel();
}

void UInsimulPauseMenuWidget::OnLoadSlotClicked(int32 SlotIndex)
{
    FString SlotName = FString::Printf(TEXT("InsimulSave_%d"), SlotIndex);
    UInsimulSaveGame* LoadedSave = Cast<UInsimulSaveGame>(UGameplayStatics::LoadGameFromSlot(SlotName, 0));
    if (!LoadedSave) return;

    // Restore player position
    APawn* PlayerPawn = GetOwningPlayerPawn();
    if (PlayerPawn)
    {
        PlayerPawn->SetActorLocation(LoadedSave->PlayerLocation);
        PlayerPawn->SetActorRotation(LoadedSave->PlayerRotation);
    }

    UE_LOG(LogTemp, Log, TEXT("[InsimulPauseMenu] Game loaded from slot %d"), SlotIndex);
    ClosePauseMenu();
}

void UInsimulPauseMenuWidget::OnSaveLoadBackClicked()
{
    ShowMainPanel();
}
